<template>
  <view class="page-container">
    <!-- <text class="page-title">康复训练指南</text> -->

    <!-- 疾病筛选 -->
    <view class="filter-box">
      <u-dropdown>
        <u-dropdown-item v-model="filterDisease" :options="diseaseOptions" @change="onFilterChange"></u-dropdown-item>
        <u-dropdown-item v-model="filterStage" :options="stageOptions" @change="onFilterChange"></u-dropdown-item>
      </u-dropdown>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading && list.length === 0" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 训练列表 -->
    <view v-else class="list-box">
      <view
        v-for="item in list"
        :key="item.id"
        class="guide-item"
      >
        <text class="item-title">{{ item.title }}</text>

        <text class="item-sub">
          类型：{{ item.type }} | 阶段：{{ getStageLabel(item.stage) }}
        </text>

        <text class="item-desc">{{ item.desc }}</text>

        <!-- 操作按钮 -->
        <view class="item-actions">
          <u-button size="mini" type="primary" @click="viewDetails(item)">
            查看详情
          </u-button>
          <u-button size="mini" plain @click="downloadGuide(item)">
            下载 PDF
          </u-button>
        </view>
      </view>

      <!-- 空状态 -->
      <u-empty v-if="!loading && list.length === 0" mode="data" description="暂无训练指南"></u-empty>

      <!-- 加载更多 -->
      <u-loadmore 
        :status="loadStatus" 
        :loading-text="'加载中...'"
        :loadmore-text="'上拉加载更多'"
        :nomore-text="'没有更多了'"
        @loadmore="onLoadMore"
        v-if="list.length > 0"
      />
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 筛选条件
const filterDisease = ref('all')
const filterStage = ref('all')

// 分页
const currentPage = ref(1)
const pageSize = ref(10)
const total = ref(0)
const loadStatus = ref<'loading' | 'loadmore' | 'nomore'>('loadmore')

// 筛选项
const diseaseOptions = ref<{ text: string; value: string }[]>([])
const stageOptions = ref<{ text: string; value: string }[]>([])

// 列表数据
const list = ref<any[]>([])
const loading = ref(false)

// 阶段标签映射
const stageLabels: Record<string, string> = {
  early: '早期',
  mid: '中期',
  late: '晚期'
}

const getStageLabel = (stage: string) => {
  return stageLabels[stage] || stage
}

// 获取筛选选项
const fetchOptions = async () => {
  try {
    const res = await request.get('/api/resource/rehab/dictionaries')
    const data = res.data || res.data || {}

    if (data.diseases && Array.isArray(data.diseases)) {
      diseaseOptions.value = [
        { text: '全部疾病', value: 'all' },
        ...data.diseases.map((item: any) => ({
          text: item.label || item.text,
          value: item.value || item.id
        }))
      ]
    }

    if (data.stages && Array.isArray(data.stages)) {
      stageOptions.value = [
        { text: '全部阶段', value: 'all' },
        ...data.stages.map((item: any) => ({
          text: item.label || item.text,
          value: item.value || item.id
        }))
      ]
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/RehabGuide.vue:120','获取筛选选项失败:', error)
    diseaseOptions.value = [{ text: '全部疾病', value: 'all' }]
    stageOptions.value = [{ text: '全部阶段', value: 'all' }]
  }
}

// 获取训练列表
const fetchTrainings = async (isRefresh = false) => {
  if (isRefresh) {
    currentPage.value = 1
    list.value = []
    loadStatus.value = 'loading'
  }
  
  if (loadStatus.value === 'nomore' && !isRefresh) return

  loading.value = true
  
  try {
    const params: Record<string, any> = {
      page: currentPage.value,
      pageSize: pageSize.value
    }
    if (filterDisease.value !== 'all') params.disease = filterDisease.value
    if (filterStage.value !== 'all') params.stage = filterStage.value

    const res = await request.get('/api/resource/rehab/trainings', { params })
    const responseData = res.data || res.data || {}
    const records = responseData.list || []
    
    list.value.push(...records)
    total.value = responseData.total || 0
    
    if (records.length < pageSize.value) {
      loadStatus.value = 'nomore'
    } else {
      loadStatus.value = 'loadmore'
      currentPage.value++
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/RehabGuide.vue:160','获取列表失败:', error)
    uni.showToast({ title: '加载失败', icon: 'none' })
    loadStatus.value = 'loadmore'
  } finally {
    loading.value = false
  }
}

// 上拉加载
const onLoadMore = () => {
  fetchTrainings()
}

// 筛选变化
const onFilterChange = () => {
  fetchTrainings(true)
}

// 查看详情
const viewDetails = (item: any) => {
  if (!item?.id) {
    uni.showToast({ title: '指南信息不完整', icon: 'none' })
    return
  }
  uni.navigateTo({
    url: `/pages/resource/rehab/RehabGuideDetail?id=${item.id}`
  })
}

// 下载 PDF 版
const downloadGuide = async (item: any) => {
  uni.showLoading({ title: '准备下载...' })
  try {
    // #ifdef H5
    const res = await request.get(`/api/resource/rehab/trainings/${item.id}/resource`, {
      params: { type: 'pdf' },
      responseType: 'blob'
    })
    const blob = new Blob([res.data], { type: 'application/pdf' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${item.title}.pdf`
    a.click()
    URL.revokeObjectURL(url)
    uni.hideLoading()
    uni.showToast({ title: '下载已开始', icon: 'success' })
    
    // 非H5端建议使用 uni.downloadFile + uni.openDocument
    const baseUrl = (request as any).defaults?.baseURL || ''
    const pdfUrl = `${baseUrl}/api/resource/rehab/trainings/${item.id}/resource?type=pdf`
    
    uni.downloadFile({
      url: pdfUrl,
      success: (res) => {
        uni.hideLoading()
        if (res.statusCode === 200) {
          uni.openDocument({
            filePath: res.tempFilePath,
            fileType: 'pdf',
            success: () => {},
            fail: () => uni.showToast({ title: '打开失败', icon: 'none' })
          })
        } else {
          uni.showToast({ title: '下载失败', icon: 'none' })
        }
      },
      fail: () => {
        uni.hideLoading()
        uni.showToast({ title: '网络错误', icon: 'none' })
      }
    })
  } catch (error) {
    uni.hideLoading()
    uni.__f__('error','at pages/resource/rehab/RehabGuide.vue:234','下载失败:', error)
    uni.showToast({ title: '下载失败', icon: 'none' })
  }
}

onMounted(() => {
  fetchOptions()
  fetchTrainings()
})
</script>

